// Normalise le message entrant (texte ou interaction)
const msg = $input.first().json;
const value = msg.entry?.[0]?.changes?.[0]?.value || msg;
const waMsg = value.messages?.[0] || {};
const from = waMsg.from;
if (!from) return [];
let text = waMsg.text?.body || '';
const interactiveId = waMsg.interactive?.button_reply?.id || waMsg.interactive?.list_reply?.id || '';
const userMessage = text || interactiveId;
const sessionId = 'whatsapp_' + from;
const orderRef = 'CMD-' + from + '-' + Date.now();
return [{
  json: {
    chatId: from,
    userMessage,
    userName: 'Client',
    sessionId,
    orderRef,
    isCallback: !!interactiveId
  }
}];

// Analyse la commande utilisateur et route
const input = $input.first().json;
const msg = input.userMessage ? input.userMessage.trim() : '';
const msgLower = msg.toLowerCase();
const chatId = input.chatId;
let routeTo = 'agent';
let vendorId = '', catId = '', prodId = '', price = '', productName = '';
let offset = 0;
const sd = $getWorkflowStaticData('global');
if (!sd.sessions) sd.sessions = {};
if (!sd.sessions[chatId]) sd.sessions[chatId] = { enCommande: false };
const salutations = ['bjr', 'bonjour', 'slt', 'salut', 'cc', 'hello', 'hey', 'bonsoir'];
const estUneSalutation = salutations.some(s => msgLower.startsWith(s));
if (msg.startsWith('VENDOR|')) {
  vendorId = msg.split('|')[1];
  routeTo = 'categories';
} else if (msg.startsWith('CAT|')) {
  const parts = msg.split('|');
  catId = parts[1]; vendorId = parts[2];
  routeTo = 'products';
} else if (msg.startsWith('PROD|')) {
  const parts = msg.split('|');
  prodId = parts[1]; catId = parts[2]; vendorId = parts[3]; price = parts[4];
  routeTo = 'productDetail';
} else if (msg.startsWith('PAGE|')) {
  const parts = msg.split('|');
  catId = parts[1]; offset = parseInt(parts[2]); vendorId = parts[3];
  routeTo = 'products';
} else if (msg.startsWith('BACK_CAT|')) {
  const parts = msg.split('|');
  catId = parts[1]; offset = parseInt(parts[2]); vendorId = parts[3];
  routeTo = 'products';
} else if (msg.startsWith('ADD_CART|')) {
  const parts = msg.split('|');
  prodId = parts[1]; price = parts[2]; catId = parts[3]; vendorId = parts[4];
  productName = parts.slice(5).join('|');
  routeTo = 'addToCart';
} else if (msg === 'VIEW_CART') {
  routeTo = 'viewCart';
} else if (msg.startsWith('REMOVE_CART|')) {
  prodId = msg.split('|')[1];
  routeTo = 'removeFromCart';
} else if (msg === 'ORDER_CART') {
  routeTo = 'orderCart';
} else if (msg.startsWith('ORDER|')) {
  const parts = msg.split('|');
  prodId = parts[1]; price = parts[2]; catId = parts[3]; vendorId = parts[4];
  productName = parts.slice(5).join('|');
  routeTo = 'agent';
  sd.sessions[chatId].enCommande = true;
} else if (msg === 'HOME' || msg === '/start') {
  routeTo = 'vendors';
  sd.sessions[chatId].enCommande = false;
} else {
  // Texte libre
  if (estUneSalutation) {
    routeTo = 'vendors';
    sd.sessions[chatId].enCommande = false;
  } else if (sd.sessions[chatId].enCommande || !input.isCallback) {
    routeTo = 'agent';
  } else {
    routeTo = 'vendors';
  }
}
return [{ json: { ...input, routeTo, vendorId, catId, offset, prodId, price, productName } }];

const rows = $input.all().map(i => i.json).filter(v => v.id);
const nav = $('Router navigation').first().json;
if (!rows.length) {
  return [{ json: { chatId: nav.chatId, type: 'buttons', text: 'Aucune boutique disponible.', buttons: [{ id: 'HOME', title: '🏠 Accueil' }] } }];
}
const sections = [{
  title: 'Boutiques',
  rows: rows.slice(0, 10).map(v => ({ id: 'VENDOR|' + v.id, title: v.nom_boutique.substring(0, 24), description: '' }))
}];
return [{ json: { chatId: nav.chatId, type: 'list', text: 'Bienvenue sur Ecom SAS Marketplace ! Choisissez une boutique :', sections, buttonText: 'Voir les boutiques' } }];

const rows = $input.all().map(i => i.json).filter(c => c.id);
const nav = $('Router navigation').first().json;
if (!rows.length) {
  return [{ json: { chatId: nav.chatId, type: 'buttons', text: 'Aucune catégorie trouvée.', buttons: [{ id: 'HOME', title: '🏠 Accueil' }] } }];
}
const sections = [{
  title: 'Catégories',
  rows: rows.slice(0, 10).map(c => ({ id: 'CAT|' + c.id + '|' + nav.vendorId, title: c.nom.substring(0, 24), description: '' }))
}];
return [{ json: { chatId: nav.chatId, type: 'list', text: 'Choisissez une catégorie :', sections, buttonText: 'Voir catégories' } }];

const rows = $input.all().map(i => i.json).filter(p => p.id);
const nav = $('Router navigation').first().json;
if (!rows.length) {
  return [{ json: { chatId: nav.chatId, type: 'buttons', text: 'Aucun produit dans cette catégorie.', buttons: [{ id: 'HOME', title: '🏠 Accueil' }] } }];
}
const total = rows[0]._total || rows.length;
const currentOffset = nav.offset || 0;
const productRows = rows.map(p => {
  const suffix = ' — ' + p.prix + '$';
  const maxNom = 24 - suffix.length;
  const nom = p.nom.substring(0, maxNom > 0 ? maxNom : 1);
  const title = (nom + suffix).substring(0, 24);
  return {
    id: 'PROD|' + p.id + '|' + nav.catId + '|' + nav.vendorId + '|' + p.prix,
    title: title,
    description: p.nom.substring(0, 72)
  };
});
if (total > currentOffset + 5) {
  productRows.push({
    id: 'PAGE|' + nav.catId + '|' + (currentOffset + 5) + '|' + nav.vendorId,
    title: '➡️ Page suivante',
    description: ''
  });
}
const sections = [{ title: 'Produits', rows: productRows }];
return [{ json: { chatId: nav.chatId, type: 'list', text: 'Produits disponibles :', sections, buttonText: 'Voir produits' } }];

const BASE_URL = 'https://mhbeauty.shop/storage/';
const nav = $('Router navigation').first().json;
const p = $input.first().json;
if (!p || !p.id) {
  return [{ json: { chatId: nav.chatId, type: 'buttons', text: 'Produit introuvable.', buttons: [{ id: 'HOME', title: '🏠 Accueil' }] } }];
}
const rawUrl = (p.photo_url || '').trim();
const photoUrl = rawUrl ? (rawUrl.startsWith('http') ? rawUrl : BASE_URL + rawUrl.replace(/^\//, '')) : '';
const caption = `📦 *${p.nom}*\n\n${p.description || ''}\n\n💰 Prix : ${p.prix}$\n📏 Taille : ${p.taille || 'N/A'}`;
const addCart = `ADD_CART|${p.id}|${p.prix}|${nav.catId}|${nav.vendorId}|${p.nom}`;
const backCat = `BACK_CAT|${p.categorie_id}|0|${nav.vendorId}`;
const order = `ORDER|${p.id}|${p.prix}|${nav.catId}|${nav.vendorId}|${p.nom}`;
const buttons = [
  { id: addCart, title: '🛒 Ajouter panier' },
  { id: backCat, title: '🔙 Continuer' },
  { id: order, title: '✅ Commander' }
];
if (photoUrl) {
  return [{ json: { chatId: nav.chatId, type: 'image', image: { link: photoUrl, caption: caption }, buttons: buttons } }];
} else {
  return [{ json: { chatId: nav.chatId, type: 'buttons', text: caption, buttons: buttons } }];
}

const input = $input.first().json;
const chatId = input.chatId;
const action = input.routeTo;
const sd = $getWorkflowStaticData('node');
if (!sd.paniers) sd.paniers = {};
if (!sd.paniers[chatId]) sd.paniers[chatId] = [];
let panier = sd.paniers[chatId];
if (action === 'addToCart') {
  const idx = panier.findIndex(i => i.prodId == input.prodId);
  if (idx >= 0) panier[idx].qty++;
  else panier.push({ prodId: input.prodId, nom: input.productName, prix: Number(input.price), vendorId: input.vendorId, catId: input.catId, qty: 1 });
  sd.paniers[chatId] = panier;
  return [{ json: { chatId, type: 'buttons', text: `✅ *${input.productName}* ajouté au panier !`, buttons: [
    { id: 'VIEW_CART', title: `🛍️ Panier (${panier.length})` },
    { id: `BACK_CAT|${input.catId}|0|${input.vendorId}`, title: '🔙 Continuer' },
    { id: 'HOME', title: '🏠 Accueil' }
  ], _isCartDisplay: true } }];
}
if (action === 'removeFromCart') {
  panier = panier.filter(i => i.prodId != input.prodId);
  sd.paniers[chatId] = panier;
  return [{ json: { chatId, type: 'buttons', text: '🗑️ Article retiré.', buttons: [
    { id: 'VIEW_CART', title: `🛍️ Panier (${panier.length})` },
    { id: 'HOME', title: '🏠 Accueil' }
  ], _isCartDisplay: true } }];
}
if (action === 'orderCart') {
  if (!panier.length) {
    return [{ json: { chatId, type: 'buttons', text: '🛒 Panier vide.', buttons: [{ id: 'HOME', title: '🏠 Accueil' }], _isCartDisplay: true } }];
  }
  let total = 0;
  let desc = '';
  const vendorId = panier[0].vendorId;
  panier.forEach(item => {
    const sous = item.prix * item.qty;
    total += sous;
    desc += `• ${item.nom} x${item.qty} = ${sous.toFixed(2)}$ `;
  });
  const safeProductName = `COMMANDE PANIER: ${desc.trim()} | Total : ${total.toFixed(2)}$`;
  sd.paniers[chatId] = [];
  const sdGlobal = $getWorkflowStaticData('global');
  if (!sdGlobal.sessions) sdGlobal.sessions = {};
  if (!sdGlobal.sessions[chatId]) sdGlobal.sessions[chatId] = {};
  sdGlobal.sessions[chatId].enCommande = true;
  return [{ json: {
    chatId,
    userMessage: safeProductName,
    userName: input.userName || 'Client',
    sessionId: input.sessionId,
    orderRef: input.orderRef,
    routeTo: 'agent',
    vendorId,
    prodId: '',
    price: total.toFixed(2),
    productName: safeProductName,
    _isCartDisplay: false
  } }];
}
// viewCart
if (!panier.length) {
  return [{ json: { chatId, type: 'buttons', text: '🛒 Votre panier est vide.', buttons: [{ id: 'HOME', title: '🏠 Accueil' }], _isCartDisplay: true } }];
}
let total = 0;
let textMsg = '🛒 *Votre panier :*\n\n';
const btns = [];
panier.forEach((item, idx) => {
  const sous = item.prix * item.qty;
  total += sous;
  textMsg += `${idx+1}. ${item.nom}\n   ${item.qty} × ${item.prix}$ = ${sous.toFixed(2)}$\n\n`;
  if (btns.length < 2) btns.push({ id: `REMOVE_CART|${item.prodId}`, title: `🗑️ ${item.nom.substring(0, 15)}` });
});
textMsg += `──────────────\n💰 *Total : ${total.toFixed(2)}$*`;
btns.push({ id: 'ORDER_CART', title: '✅ Commander' });
return [{ json: { chatId, type: 'buttons', text: textMsg, buttons: btns, _isCartDisplay: true } }];

