// Parse la réponse de l'Agent IA
const agentOutput = $input.first().json;
const response = agentOutput.output || '';
let chatId = agentOutput.chatId;
if (!chatId) {
  try { chatId = $('Router navigation').first().json.chatId; } catch(e) {}
}
if (!chatId) {
  try { chatId = $('Normaliser message').first().json.chatId; } catch(e) {}
}
// Réinitialiser enCommande si la commande est confirmée
const sd = $getWorkflowStaticData('global');
if (sd.sessions && sd.sessions[chatId]) {
  if (/CMD-|commande\s*(n°|numero|numéro|#)|confirmée|confirmé|paiement/i.test(response)) {
    sd.sessions[chatId].enCommande = false;
  }
}
// Construire les boutons de retour
const buttons = [
  { id: 'HOME', title: '🏠 Accueil' }
];
// Si c'est une demande d'infos (étape 3 du flow commande), garder simple
const isAskingInfo = /nom|téléphone|adresse|livraison/i.test(response);
const text = response || 'Je n\'ai pas compris. Tapez HOME pour revenir à l\'accueil.';
return [{ json: {
  chatId,
  type: 'buttons',
  text: text,
  buttons: isAskingInfo ? [] : buttons
} }];

// Adaptateur pour l'API WhatsApp v22.0
const input = $input.first().json;
let chatId = input.chatId;
if (!chatId) {
  try { chatId = $('Router navigation').first().json.chatId; } catch(e) {}
}
if (!chatId) return [];
const to = String(chatId).replace(/^\+/, '');
const type = input.type;
const text = input.text || '';
const buttons = (input.buttons || []).filter(b => b.id && (b.title || b.text));
const sections = input.sections || [];
const buttonText = input.buttonText || 'Choisir';
const image = input.image || null;
let payload = { messaging_product: 'whatsapp', to: to, type: 'text' };
if (type === 'list' && sections.length > 0) {
  payload.type = 'interactive';
  payload.interactive = {
    type: 'list',
    body: { text: text || '.' },
    action: { button: buttonText.substring(0, 20), sections: sections }
  };
} else if (type === 'image' && image) {
  // Envoyer l'image d'abord (sans boutons), les boutons en message séparé
  payload.type = 'image';
  payload.image = image;
} else if (buttons.length > 0) {
  const validBtns = buttons.slice(0, 3).map(b => ({
    type: 'reply',
    reply: {
      id: String(b.id).substring(0, 256),
      title: String(b.title || b.text || '').substring(0, 20)
    }
  }));
  payload.type = 'interactive';
  payload.interactive = {
    type: 'button',
    body: { text: (text || '.').substring(0, 1024) },
    action: { buttons: validBtns }
  };
} else {
  payload.type = 'text';
  payload.text = { body: (text || '.').substring(0, 4096), preview_url: false };
}
return [{ json: payload }];
